member.example:
基本使用：

// 初始化 LUT（游戏启动时）
FPLut.InitializeBuiltIn();

// 创建定点数
FP a = 3.5;                    // 隐式转换
FP b = FP.FromRaw(FP.Raw._1_50);  // 使用原始常量

// 数学运算
FP c = a * b;                // 乘法（四舍五入）
FP d = FP.Sqrt(c);           // 平方根
FP e = FP.Sin(a);            // 正弦

example.code:
// 在物理引擎的紧循环中使用无分支版本
for (int i = 0; i < particles.Count; i++)
{
    FP velocity = particle.Velocity;
    FP damping = FP.AbsBranchless(velocity) * friction;
}

// 在碰撞检测的 AABB 检查中使用
FP minX = FP.MinBranchless(a.Min.X, b.Min.X);
FP minY = FP.MinBranchless(a.Min.Y, b.Min.Y);

// 在输入处理中限制摇杆值
FP clampedX = FP.ClampBranchless(input.X, -FP._1, FP._1);
FP clampedY = FP.ClampBranchless(input.Y, -FP._1, FP._1);

// 检查是否到达目标位置（考虑浮点误差）
if (FP.Approximately(currentPos, targetPos))
{
    // 到达目标
}

// 使用较大容差检查速度是否接近零
if (FP.Approximately(velocity, FP._0, (FP)0.01))
{
    velocity = FP._0; // 完全停止
}

FP[] source = new FP[100];
FP[] dest = new FP[100];

fixed (FP* src = source)
fixed (FP* dst = dest)
{
    FPUnsafe.Copy(src, dst, 100);
}

